                        "isDebuff": true,
                        "element": "Wind",
                        isAllDOTTypes: true,
                        multiplier: values[0],
                        multiPerStack: values[2],
                        multiStackCap: 50 + (rank>=6 ? 30 : 0),
                        softCapDetonate: 50 + (rank>=6 ? 30 : 0),
                        scalar: "ATK",
                        slot: skillRef.slot,
                        ownerIsAllied: true,
                        ownerSlot: sourceTurn.name,
                        avgChanceApplied: 1,
